#include <stdio.h>
#include <stdlib.h>
typedef struct Edge {
    int u, v;
} Edge;
int main() {
    int n, m;
    scanf("%d %d", &n, &m);
    Edge* edges = (Edge*)malloc(m * sizeof(Edge));
    for (int i = 0; i < m; i++) {
        scanf("%d %d", &edges[i].u, &edges[i].v);
    }
    // Print the graph representation
    for (int i = 0; i < m; i++) {
        printf("%d %d\n", edges[i].u, edges[i].v);
    }
    free(edges);
    return 0;
}

